import{_ as e,o as l,c as i,a2 as r}from"./chunks/framework.Cr-Z7ngm.js";const c=JSON.parse('{"title":"融资常见问题","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"margin/faq.md","filePath":"zh-CN/margin/faq.md"}'),t={name:"margin/faq.md"};function o(h,a,n,p,d,s){return l(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="融资常见问题" tabindex="-1">融资常见问题 <a class="header-anchor" href="#融资常见问题" aria-label="Permalink to &quot;融资常见问题&quot;">​</a></h1><p>融资额度评估、保证金体系、融资利息计算、额度调整及偿还方式。</p><h2 id="如何查询股票是否支持融资交易" tabindex="-1">如何查询股票是否支持融资交易 <a class="header-anchor" href="#如何查询股票是否支持融资交易" aria-label="Permalink to &quot;如何查询股票是否支持融资交易&quot;">​</a></h2><p>在相应股票的个股详情页 &gt; 行情 &gt; 股票当前价格 &gt; 右侧 icon，即可查看该股票是否支持融资交易及当前保证金系数。</p><h2 id="综合账户融资概述" tabindex="-1">综合账户融资概述 <a class="header-anchor" href="#综合账户融资概述" aria-label="Permalink to &quot;综合账户融资概述&quot;">​</a></h2><p>长桥综合账户支持通过保证金融资提高投资购买力。</p><p>账户的融资额度会根据您存入的现金或转仓情况自动评估。额度调整可在 App 资产页的「融资状态」入口发起，或联系客户经理。</p><p>保证金体系包含三个层级：</p><ul><li>初始保证金 (IM)：建仓时需存入的保证金要求</li><li>维持保证金 (MM)：股权资产需维持的水平</li><li>平仓保证金 (FM)：当股权资产低于此水平时，持仓可能被即时强平</li></ul><p>计算公式：</p><ul><li>股权资产 = 现金余额 + 投资组合总市值</li><li>可用资金（包含融资）= 股权资产 - 初始保证金要求 - 冻结资金</li><li>最大购买力 = 可用资金 / 初始保证金（IM）</li></ul><h2 id="融资利息相关问题" tabindex="-1">融资利息相关问题 <a class="header-anchor" href="#融资利息相关问题" aria-label="Permalink to &quot;融资利息相关问题&quot;">​</a></h2><h3 id="融资利息如何计算" tabindex="-1">融资利息如何计算 <a class="header-anchor" href="#融资利息如何计算" aria-label="Permalink to &quot;融资利息如何计算&quot;">​</a></h3><p>融资利息以交收结算后的账户实际金额进行计息。</p><ul><li>长桥香港：当日融资利息 = 当日交易日闭市后融资余额 × 融资利率 / 365</li><li>长桥新加坡：当日融资利息 = 交易日 18:00 SGT 的融资余额 × 年融资利率 / 365</li></ul><p>最低 0.01 单个币种，不足则不计息。融资天数以 365 天为一年，按自然日计算，日计月结。</p><p>详细计算规则及不计息情形请参考：<a href="/margin/融资利息规则">融资利息规则</a></p><h3 id="融资利率是否会变化" tabindex="-1">融资利率是否会变化 <a class="header-anchor" href="#融资利率是否会变化" aria-label="Permalink to &quot;融资利率是否会变化&quot;">​</a></h3><p>是的。融资利率可能在不预先通知的情况下进行周期性调整，以适应货币汇率的变化。</p><h2 id="额度调整" tabindex="-1">额度调整 <a class="header-anchor" href="#额度调整" aria-label="Permalink to &quot;额度调整&quot;">​</a></h2><p>融资额度支持在 App 内按需提高或降低，每 24 小时内最多申请 2 次（新加坡账户每 24 小时限 1 次）。详细操作参见<a href="/margin/如何关闭或降低融资额度">如何关闭或降低融资额度</a>。</p><h2 id="偿还融资欠款" tabindex="-1">偿还融资欠款 <a class="header-anchor" href="#偿还融资欠款" aria-label="Permalink to &quot;偿还融资欠款&quot;">​</a></h2><h3 id="偿还方式" tabindex="-1">偿还方式 <a class="header-anchor" href="#偿还方式" aria-label="Permalink to &quot;偿还方式&quot;">​</a></h3><p>目前偿还融资欠款一般有三种方式：</p><ol><li>货币兑换：其他货币有余额足够偿还融资欠款，可使用货币兑换功能兑换成相应币种用于补足欠款</li><li>入金：客户入金后会优先补足欠款，补足欠款的部分在入金到账后将不再计息</li><li>卖出股票：卖出股票后需等待清算完成。港股 T+2、美股 T+1 清算，在卖出后的等待期内账户依然有欠款并产生融资利息</li></ol><h3 id="偿还时间与清算节点" tabindex="-1">偿还时间与清算节点 <a class="header-anchor" href="#偿还时间与清算节点" aria-label="Permalink to &quot;偿还时间与清算节点&quot;">​</a></h3><ul><li>长桥香港：美/港股清算时间点为每交易日 17:00（香港时间）</li><li>长桥新加坡：新加坡/美国/香港股票的结算时间为每个交易日 18:00（新加坡时间）</li></ul><p>示例（香港）：</p><ul><li>例一：客户于 1 月 1 日（香港时间）使用融资购买了港股，账务日期为 1 月 1 日。客户于 1 月 3 日 17:00（香港时间）之前存入该笔交易款项（连同相关交易费用），将不会产生融资利息。</li><li>例二：客户于 1 月 1 日（香港时间）使用融资购买了美股，账务日期为 1 月 2 日。客户于 1 月 3 日 17:00（香港时间）之前存入该笔交易款项（连同相关交易费用），将不会产生融资利息。</li></ul><h2 id="日内融资交易" tabindex="-1">日内融资交易 <a class="header-anchor" href="#日内融资交易" aria-label="Permalink to &quot;日内融资交易&quot;">​</a></h2><p>日内融资是指在同一交易日内使用融资买入并于当日平仓的交易方式。</p><p>主要特点：必须于收盘前 15 分钟平仓至满足保证金要求，否则长桥证券会执行强制平仓机制，在没有事前通知的情况下替客户平仓至无欠款并取消所有订单。</p><p>详细内容（支持市场、下单时间、额度限制、极端天气安排等）请参考日内融账户相关文档。</p><h2 id="余额通与融资" tabindex="-1">余额通与融资 <a class="header-anchor" href="#余额通与融资" aria-label="Permalink to &quot;余额通与融资&quot;">​</a></h2><p>您可选择加入余额通管理服务。余额通是长桥证券（香港）有限公司推出的一款闲置资金理财产品，为客户提供现金增值服务，既满足客户随时买股票的需求，又能为客户的闲置资金创造收益。</p><p>加入后，多余的港币及美元资金将酌情用于投资货币市场基金。余额通资产计入股权资产，在计算风控状态时一并纳入。</p><p>更多详情请参阅长桥 App 中关于余额通的部分。</p>',37)])])}const q=e(t,[["render",o]]);export{c as __pageData,q as default};
